/**
 * Handle user updated — notify user of account changes.
 */
private async handleUserUpdated(event: UserUpdatedEvent): Promise<void> {
  await this.send({
    type: 'account-updated',
    channel: 'email',
    recipient: event.user.email,
    subject: 'Account Updated',
    body: `Hi ${event.user.name}, your account has been updated. Changes: ${event.changes.join(', ')}.`,
    priority: 'low',
    metadata: { userId: event.user.id },
  });
}

